"""
MKT Original Commentary — 2 Corinthians chapters 1-5
Run: python3 scripts/zc-original-2corinthians-1-5.py

Key translation decisions for chs 1-5:
- parakaleo / paraklesis (comfort/consolation/exhort): MKT renders consistently as
  'comfort'/'comforts' throughout 1:3-7 to preserve the verbal root-link; the same
  Greek word family also means 'encourage/exhort' but the comfort-thread here is
  deliberate.
- sarx (1:17): rendered 'worldly manner' — lit. 'according to flesh'; MKT preserves
  the Pauline sarx idiom.
- thriambeuo (2:14): 'leads in triumphal procession' — the Roman triumph image; Paul
  is the captive/prisoner displayed in Caesar's parade.
- grammata / pneuma (3:6): 'written code'/'Spirit' — the letter/spirit distinction;
  MKT keeps 'written code' to be precise.
- Kyrios = Spirit identification (3:17): contested; MKT renders literally.
- aion (4:4): 'age' not 'world' — precise temporal sense; the adversary rules the
  present evil age, not a spatial territory.
- kainos ktisis (5:17): 'new creation' — cosmic and eschatological, not merely
  personal; MKT retains over 'new creature'.
- hamartion (5:21): 'sin' as the abstract power; God made Christ to be sin-itself.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIGINAL = {
  "1": {
    "1": '<p><em>Paulos, apostolos Christou Iesou dia thelematos theou</em> — mirrors 1 Cor 1:1 almost exactly. <em>Apostolos</em> (lit. \'one sent\') carries official commission; Paul uses it defensively throughout 2 Cor against those who question his authority. <em>Dia thelematos theou</em> (through the will of God): his apostleship is not self-appointed but divinely initiated. <em>Hagiois</em> (the saints, dispute level 2): MKT renders \'church\' for the corporate body of those \'set apart\' (<em>hagios</em>). The letter addressed to all Achaia — broader than Corinth, suggesting intended circulation.</p>',
    "2": '<p>Standard Pauline greeting combining Greek (<em>charis</em>, grace) and Hebrew (<em>eirene</em>, peace = shalom). <em>Charis</em> (dispute level 2): MKT \'grace\' — unmerited divine favour as the source of all apostolic work. <em>Apo theou patros hemon kai kyriou Iesou Christou</em>: the double genitive presents both God and Christ as joint source of grace and peace — a high-Christology formula.</p>',
    "3": '<p><em>Eulogetos ho theos kai pater tou kyriou hemon Iesou Christou</em>: Paul opens with a berakah (Jewish blessing formula), identifying the God of Israel as the Father of Jesus. <em>Paraklesis</em> (dispute level 2, appears 10x in vv.3-7): MKT \'comfort/consolation\'; Greek range includes \'encouragement,\' \'exhortation,\' \'appeal.\' The consistent use creates a verbal network around divine strengthening in suffering. <em>Pater oiktirmon</em> (Father of compassion): <em>oiktirmon</em> translates Hebrew <em>rachamim</em> (womb-derived mercy).</p>',
    "4": '<p><em>Ho parakalon hemas epi pase te thlipsei hemon</em>: God comforts in all <em>thlipsis</em> (pressure, affliction, distress — lit. squeezing). The result clause: <em>eis to dynasthai hemas parakalesai</em> (so that we are able to comfort) — capacity to comfort others flows from received comfort. <em>Dia tes parakleseos</em>: through the same comfort. The mechanism is participation: received comfort flows through Paul to others. This is the theological model for his apostolic ministry of shared suffering.</p>',
    "5": '<p><em>Hoti kathos perisseui ta pathemata tou Christou eis hemas</em>: the overflow logic. <em>Pathemata tou Christou</em> (the sufferings of Christ): not merely Christ\'s past sufferings but the pattern of suffering that characterizes participation in Christ\'s mission. <em>Perisseuo</em> (overflow/abound): same verb for both sufferings and comfort — they overflow in equal measure. MKT \'sufferings of Christ overflow into our lives\' captures the participatory sense.</p>',
    "6": '<p><em>Eite de thlibometha hyper tes hymon parakleseos kai soterias</em>: Paul\'s suffering serves the Corinthians\' comfort and salvation; his being comforted serves their comfort. The circular economy of suffering and comfort is explicitly apostolic. <em>Energoumenes en hypomone</em> (produced in endurance): the comfort produces patient endurance in the midst of the same sufferings Paul experiences.</p>',
    "7": '<p><em>Kai he elpis hemon bebaia hyper hymon</em>: <em>elpis</em> (hope, dispute level 2) is \'firm/stable\' (<em>bebaios</em> — certain, ratified, legally valid). <em>Koinonoi este ton pathematon</em> (you share in the sufferings): the basis of the firm hope is shared participation — not optimism but theological knowledge of mutuality in Christ.</p>',
    "8": '<p><em>Ou gar thelomen hymas agnoein</em> (we do not want you to be unaware): disclosure formula introducing the Asia hardship. <em>Baros hyper dynamin</em> (burdened beyond ability): Paul was crushed beyond capacity — existentially overwhelmed. <em>Hoste exaporethena kai tou zen</em>: to the point of despairing even of life. The extremity was genuine, not rhetorical.</p>',
    "9": '<p><em>Alla auto en heautois to apokrima tou thanatou eschekamen</em>: we had within ourselves the sentence of death (<em>apokrima</em> — the official verdict). Purpose clause: so they would not rely on themselves but on God who raises the dead. The resurrection-God becomes the only viable source of hope — a theological reorientation forced by the extremity of the crisis.</p>',
    "10": '<p><em>Hos ek telikoutos thanatou errysato hemas kai rhysetai</em>: triple rescue tense — rescued (aorist), will rescue (future), on him we set our hope (present). <em>Rhyomai</em> (deliver/rescue): the verb of liberation used for God\'s OT deliverances. The escalation from past deliverance to eschatological hope grounds confidence in the same resurrection-God.</p>',
    "11": '<p><em>Synantilambomenon kai hymon hyper hemon te deesis</em>: the community\'s prayer (<em>deesis</em>, specific request) co-participates in Paul\'s rescue. <em>To eis hemas charisma</em> (the grace-gift granted to us): Paul\'s rescue is a <em>charisma</em> — not personal strength. <em>Ek pollon prosopon</em> (through many faces/persons): thanks ascend from many because many prayed.</p>',
    "12": '<p><em>He kauchesis hemon aute estin</em>: Paul\'s boast (<em>kauchesis</em>) is his conscience\'s testimony. <em>Haploteti kai eilikrineia theou</em>: in simplicity (<em>haplotes</em> — singleness, undivided integrity) and sincerity. <em>Ouk en sophia sarkike</em> (not in fleshly wisdom): he explicitly rejects worldly calculation. <em>Charis</em> (dispute level 2): God\'s grace has characterized his ministry, not rhetorical skill.</p>',
    "13": '<p><em>Ou gar alla graphomen hymin all\' e ha anaginoskete e kai epiginoskete</em>: the letters are transparent. The contrast between <em>anaginoskete</em> (read the surface) and <em>epiginoskete</em> (fully recognize/understand). Paul hopes for complete recognition: <em>heos telous</em> — to the end (completely, or until the Parousia).</p>',
    "14": '<p><em>Kathos kai epegnote hemas apo merous</em>: they have understood Paul \'in part\' (<em>apo merous</em>). The goal is full understanding: mutual <em>kauchema</em> (boasting-subject) at the Parousia. Paul and Corinth will be each other\'s crown at Christ\'s judgment — connecting to 5:10\'s accountability language.</p>',
    "15": '<p><em>Kai tauth te pepoithesei</em>: in this confidence. <em>Charin</em> (dispute level 2): MKT \'benefit twice\' — the planned double visit as grace-gift, not obligation. The travel plans were confidence-based expressions of generosity, not capricious self-interest.</p>',
    "16": '<p>The planned double visit: through Corinth to Macedonia and return, then on to Judea. <em>Propemphthena</em>: the technical term for equipping a traveler for the journey. Paul\'s abandoned itinerary becomes the occasion for accusations of fickleness that require the defense of vv.17-23.</p>',
    "17": '<p><em>Elaphria</em> (lightness, fickleness): the accusation against Paul. <em>E ha bouleuomai kata sarka bouleuomai</em>: do I plan according to flesh? <em>Sarx</em> (dispute level 2) — \'worldly manner\' in MKT; the literal \'according to flesh\' captures the Pauline idiom for self-interested, self-serving calculation. The charge: manipulative double-mindedness.</p>',
    "18": '<p><em>Pistos de ho theos</em>: God is faithful — the ground of Paul\'s own consistency. <em>Logos</em> (dispute level 2): in context, Paul\'s communicative word to them — the consistency of his speech mirrors God\'s faithful character. His word to Corinth was not Yes-and-No because God, whose servant he is, is not Yes-and-No.</p>',
    "19": '<p><em>Ho tou theou gar huios Iesous Christos ho en hymin di\' hemon kerychtheis</em>: the Son of God, Jesus Christ, proclaimed among them by Paul, Silvanus, and Timothy — three consistent witnesses. <em>Alla nai en auto gegonen</em>: in him Yes has happened. The Christological move: Christ is the Yes to all of God\'s promises (v.20), and his consistency models and grounds Paul\'s own.</p>',
    "21": '<p><em>Ho de bebaion hemas syn hymin eis Christon kai chrisas hemas theos</em>: God who confirms (<em>bebaioo</em> — legally ratifies) us together with you into Christ, and who anointed (<em>chrio</em>) us. The <em>chrio</em>/<em>Christos</em> wordplay is deliberate: the Christ is the Anointed One; we share his anointing. Participation in Christ\'s own consecration, not a separate personal ceremony.</p>',
    "22": '<p><em>Ho kai sphragisamenos hemas kai dous ton arrhabona tou pneumatos en tais kardiais hemon</em>: three participial actions of God — confirmed, sealed (<em>sphragizo</em> — ownership mark, used for goods and legal documents), and given the Spirit as <em>arrabon</em> (down-payment/pledge — commercial-legal term for earnest money guaranteeing full payment). The Spirit now is the first installment of the eschatological inheritance.</p>',
    "23": '<p><em>Ego de martyra ton theon epikaloumai epi ten emen psychen</em>: the most solemn oath formula possible, invoking divine judgment on himself if lying. <em>Hoti pheidomenos hymon ouketi elthen eis Korinthon</em>: to spare them he did not come. The journey change was pastoral, not caprice. The defense appeals to divine knowledge of motives — the same knowledge that will operate at the bema of 5:10.</p>',
    "24": '<p><em>Ouch hoti kyrieuomen hymon tes pisteos</em>: not lording over their faith (<em>kyrieuomen</em> — domination-verb). The contrast with opponents who lord authority (11:20). <em>Alla synergoi esmen tes charas hymon</em>: but fellow workers (<em>syn</em>-ergoi) of your joy. <em>Te gar pistei estekate</em>: by faith you stand — faith is the stable ground, not Pauline authority.</p>'
  },
  "2": {
    "1": '<p><em>Ekrina de emauton touto, to me en lype pros hymas elthein</em>: Paul resolved (<em>krino</em> — judged, decided) not to come in grief (<em>lype</em>). The \'painful visit\' (likely between 1 and 2 Corinthians) had already occurred — Paul visited, encountered opposition, and left. This verse is the retrospective account of the subsequent decision to write the \'tearful letter\' (v.4) rather than return immediately.</p>',
    "2": '<p><em>Ei gar ego lypeo hymas, kai tis ho euphrainas me ei me ho lypetheis ex emou</em>: the logic of mutual grief — if Paul grieves them, only they can make him glad. The pastoral paradox forces the letter-strategy: a painful visit would eliminate the relational basis for his own joy in them.</p>',
    "3": '<p><em>Kai egrapsa touto auto, hina me, elthon, lypen scho</em>: the purpose of the tearful letter — so that coming he would not have grief from those who should make him rejoice. <em>Pepoithos epi pantas hymas</em>: confident concerning all of them. Paul expected a positive communal response; confidence, not punitive pressure, was the letter\'s basis.</p>',
    "4": '<p><em>Ek gar polles thlipseos kai synochnes kardias egrapsa</em>: the letter came from great pressure (<em>thlipsis</em>, same as 1:4-8) and anguish (<em>synoche</em> — constriction, tightness) with many tears. <em>Agape</em> (dispute level 2 — self-giving love): the motivation was not to grieve but to make known love. The tearful letter was an act of agape, not coercion.</p>',
    "5": '<p><em>Ei de tis lelupen, ouk eme lelupen alla apo merous</em>: the offender grieved not Paul so much as the community — to some extent (<em>apo merous</em>). Paul distances himself from the personal wound to refocus on the community\'s collective experience. The <em>apo merous</em> (in part) avoids the appearance of petty grievance.</p>',
    "6": '<p><em>Hikanon to toiouto epitimia</em>: the punishment is sufficient (<em>hikanos</em> — adequate). The same root as 3:5-6 where the only true sufficiency comes from God. Here the community\'s corporate discipline has been sufficient; no further severity is needed. Paul now pivots toward restoration.</p>',
    "7": '<p><em>Hoste tounantion mallon hymas charisasthai kai parakalesai</em>: instead, forgive (<em>charizomai</em> — give grace to, the active charis-verb) and comfort him. <em>Katapinomai</em> (swallowed up/devoured): excessive sorrow after repentance becomes its own spiritual danger — a trap the community must prevent.</p>',
    "8": '<p><em>Dio parakaleo hymas kyrosai eis auton agapen</em>: confirm/ratify (<em>kuroo</em> — legal ratification verb) your love. The community must officially reaffirm love for the restored member. <em>Agape</em> (dispute level 2): self-giving love is the posture toward the restored person, not conditional acceptance after probation.</p>',
    "9": '<p><em>Hina gno ten dokimen hymon</em>: to know their tested quality (<em>dokime</em> — proof, approved character from testing). The testing-and-approval framework recurs in chs 10-13. Obedience here is not to Paul personally but to the apostolic pattern — the community\'s response to the tearful letter proves their character.</p>',
    "10": '<p><em>Ho de ti chariczesthe, kago</em>: Paul ratifies their forgiveness. <em>Di\' hymas en prosopo Christou</em>: for their sake in the presence of Christ (<em>prosopo Christou</em>). The forgiveness transaction occurs before the face of Christ — theological grounding of the human pastoral act.</p>',
    "11": '<p><em>Hina me pleonektethomen hypo tou Satana</em>: lest they be outwitted/defrauded by Satan. <em>Ou gar autou ta noemata agnoumen</em>: we are not unaware of his schemes (<em>noemata</em>). Leaving the offender in excessive grief would cede pastoral territory to the adversary — the spiritual warfare logic behind the restoration imperative.</p>',
    "12": '<p><em>Elthon de eis ten Troadha eis to euangelion tou Christou kai thyras moi anengmenes en kyrio</em>: arriving at Troas to preach the gospel and finding an open door. The \'open door\' (<em>thyra</em>) for missionary opportunity is Pauline idiom (1 Cor 16:9; Col 4:3) — the Lord opens doors. Despite the opportunity, anxiety over Titus drove him to Macedonia.</p>',
    "13": '<p><em>Ouk escheka anesin to pneumati mou</em>: no rest/relief (<em>anesis</em> — relaxation of tension) for his spirit (<em>pneuma</em> — the human inner self here, not the Holy Spirit). The pastoral bond with Titus was stronger than the open missionary opportunity. The emotional candor is exceptional — Paul\'s personal distress is relevant apostolic data.</p>',
    "15": '<p><em>Hoti Christou euodia esmen to theo</em>: we are the pleasing aroma (<em>euodia</em> — sweet fragrance, used for acceptable sacrifices in the LXX, e.g. Gen 8:21) of Christ to God. The triumphal procession image (v.14) includes incense. The same message functions differently for different hearers: life-smell or death-smell.</p>',
    "16": '<p><em>Hois men osme ek thanatou eis thanaton, hois de osme ek zoes eis zoen</em>: the identical aroma produces opposite effects — death-to-death for the perishing, life-to-life for the saved. The rhetorical question <em>pros tauta tis hikanos</em> (who is sufficient?) introduces the competence-theme running through ch 3: no one is inherently adequate for this ministry.</p>',
    "17": '<p><em>Ou gar esmen hos hoi polloi kapeleuontes ton logon tou theou</em>: unlike the many who peddle (<em>kapeleuo</em> — hawk for profit, like a wine-merchant watering down stock) the word of God. <em>Alla hos ex eilikrneias, alla hos ek theou, katenanti theou en Christo laloumen</em>: from sincerity (<em>eilikrineia</em> — purity tested by sunlight), from God, before God, in Christ. Four prepositional qualifiers frame authentic apostolic speech.</p>'
  },
  "3": {
    "1": '<p><em>Archometha palin heautous synistanein</em>: are we beginning again to commend ourselves? The opponents apparently arrived with <em>epistolai systatikai</em> (letters of recommendation) — formal credentials from other communities or apostles. Paul must explain why he needs no such letters without appearing to be merely self-promoting.</p>',
    "2": '<p><em>He epistole hemon hymeis este</em>: you are our letter. <em>Engegramene en tais kardiais hemon</em>: written in our hearts (variant: \'your hearts\' — MSS differ). MKT follows the \'our hearts\' reading. <em>Ginoskomene kai anaginoskomene hypo panton anthropon</em>: known and read by all people. The community\'s transformed life is publicly readable testimony — more persuasive than any papyrus recommendation.</p>',
    "3": '<p><em>Phaneroymenoi hoti este epistole Christou</em>: manifestly a letter of Christ (<em>Christou</em> — genitive of authorship; Christ authored it). <em>Diakonettheisa hyph\' hemon</em>: administered/delivered by us — Paul is the mail-carrier, not the author. <em>Pneumati theou zontos</em>: written with the Spirit of the living God. <em>Ouk en plaxin lithinais alla en plaxin kardiais sarkinais</em>: not on stone tablets but on tablets of fleshly hearts — Jer 31:33/Ezek 36:26 new-covenant fulfillment subtext.</p>',
    "4": '<p><em>Pepoithesis de toiauten echomen dia tou Christou pros ton theon</em>: such confidence (<em>pepoithesis</em> — settled trust, firm persuasion) through Christ toward God. The confidence is not in Paul\'s performance but in the Christ-mediated relationship with God — setting up the competence argument: confidence is given, not self-generated.</p>',
    "5": '<p><em>Ouch hoti aph\' heauton hikanoi esmen logisasthai ti hos ex heauton</em>: not that we are sufficient (<em>hikanos</em>) of ourselves to reckon anything as from ourselves. This answers 2:16\'s question \'who is sufficient?\' <em>All\' he hikaniotes hemon ek tou theou</em>: our sufficiency is from God. The <em>ek theou</em> entirely replaces the <em>aph\' heauton</em> — divine source, not human resource.</p>',
    "7": '<p><em>Ei de he diakonia tou thanatou en grammasin entetypomene lithou egeneto en doxe</em>: if the ministry of death (<em>diakonia tou thanatou</em>), engraved in letters on stone, came in glory so that Israel could not gaze at Moses\' face (Exod 34:29-35). The argument from Sinai\'s glory: even the old covenant had genuine divine glory, so much more the new. <em>Grammasin</em>: the written letters on stone — the same root as the letter (<em>gramma</em>) that kills (v.6).</p>',
    "8": '<p><em>Pos ouchi mallon he diakonia tou pneumatos estai en doxe</em>: how much more will the ministry of the Spirit be in glory? The <em>a fortiori</em> argument: lesser to greater, old covenant glory to new covenant glory. <em>Diakonia tou pneumatos</em>: ministry characterized by the Spirit, not by written code.</p>',
    "9": '<p><em>Ei gar te diakonia tes katakrises doxa, pollo mallon perisseuei he diakonia tes dikaiosyne en doxe</em>: if the ministry of condemnation (<em>katakrisis</em>) had glory, much more does the ministry of righteousness (<em>dikaiosyne</em>, dispute level 2) abound in glory. <em>Dikaiosyne</em> here is the judicial right-standing that the new covenant conveys — the forensic declaration of rightness before God, not merely ethical uprightness.</p>',
    "10": '<p><em>Kai gar ou dedoxastai to dedoxasmenon en touto to merei heineka tes hyperballoystes doxes</em>: what was glorious appears inglorious by comparison because of the surpassing glory. The comparison is quantitative, not qualitative negation — the old covenant was genuinely glorious; the new so far exceeds it that the old appears inglorious by contrast.</p>',
    "11": '<p><em>Ei gar to katargoumenon dia doxes, pollo mallon to menon en doxe</em>: if what is being abolished (<em>katargeo</em> — the key Pauline verb for rendering ineffective; used for powers, laws, and death in 1 Cor 15:24-26) came through glory, much more what remains (<em>meno</em>) is in glory. The permanence/temporary contrast grounds the new covenant\'s superiority.</p>',
    "12": '<p><em>Echontes oun toiauten elpida, polle parresia chrometha</em>: having such hope (<em>elpis</em>, dispute level 2) we use great boldness (<em>parresia</em> — frank speech, freedom of speech; Athenian democratic ideal; in Jewish contexts, access before God). The permanence of the new covenant (v.11) grounds Paul\'s confident, unguarded speech.</p>',
    "13": '<p><em>Kai ou katha per Mousas etithe kalymma epi to prosopon autou</em>: not like Moses who put a veil on his face to prevent Israel from seeing the end (<em>telos</em>) of the fading. <em>To katargoumenon</em>: the fading/abolishing thing. MKT \'to prevent the Israelites from seeing the end of what was passing away\' captures the Pauline reading. This is a midrashic interpretation of Exod 34 — Paul reads the veil as concealing the temporary nature of the Mosaic glory.</p>',
    "14": '<p><em>Alla eporo the ta noemata auton</em>: their minds were hardened (<em>poroo</em> — hardened as with a callus). <em>To auto kalymma epi te anagnosei tes palaias diathekes menei akalypton</em>: the same veil remains unlifted over the reading of the old covenant. <em>Hoti en Christo katargeitai</em>: because in Christ it is being abolished. The Christological key to scriptural understanding: the veil over the mind lifts only in Christ.</p>',
    "15": '<p><em>All\' heos semeron henika an anaginosketai Mousas, kalymma epi ten kardian auton keitai</em>: to this day when Moses is read, a veil lies over their hearts. The veil has migrated from Moses\' face (Exod 34) to the readers\' hearts — Paul\'s application. The problem is not the text but the hearts that read it without Christ (cf. 1 Cor 2:14).</p>',
    "16": '<p><em>Heneka de ean epistrepse pros kyrion, periaireitai to kalymma</em>: whenever anyone turns to the Lord (<em>epistrepho</em> — the conversion verb), the veil is removed. Paul reads Exod 34:34 (Moses entered the Lord\'s presence and removed the veil) as a type of conversion: turning to Christ removes the interpretive veil. The \'Lord\' of Exod 34 is applied to Christ — a Christological exegesis of the Exodus text.</p>',
    "17": '<p><em>Ho de Kyrios to pneuma estin</em>: the Lord is the Spirit. One of Paul\'s most contested identifications. The \'Lord\' of v.16 (Exod 34:34) is identified with the Spirit. MKT renders literally, preserving the identification without resolving whether ontological (Christ and Spirit are numerically one) or functional (encounter with the Spirit is encounter with the Lord). <em>Hou de to pneuma Kyriou, eleutheria</em>: where the Spirit of the Lord is, freedom (<em>eleutheria</em>) — from the veil, from condemnation, from the letter that kills.</p>'
  },
  "4": {
    "1": '<p><em>Dia touto, echontes ten diakonian tauten, kathos eleethemen, ouk ekkakomen</em>: having this ministry through mercy (<em>eleeo</em> — the compassion verb), we do not lose heart (<em>ekkakeo</em> — to be weary, give in to evil). The mercy-basis: the ministry was received as a mercy-gift, not earned — therefore hardships do not invalidate it. Endurance is grounded in grace, not personal resilience.</p>',
    "2": '<p><em>Alla apeipametha ta krypta tes aischynes</em>: renounced the hidden things of shame (<em>aischyne</em>). What Paul rejects: cunning (<em>panourgia</em> — unprincipled all-working cleverness), distorting (<em>dolountes</em> — adulterating) the word of God. <em>Alla te phanerosi tes aletheias</em>: by the open display of truth (<em>aletheia</em>). The apostolic word is transparent — nothing hidden, no manipulation of meaning.</p>',
    "3": '<p><em>Ei de kai estin kekalymmenon to euangelion hemon</em>: if the gospel is veiled. The veil of ch 3 reappears applied to the gospel. <em>En tois apollymenois estin kekalymmenon</em>: it is veiled among those who are perishing (<em>apollymi</em>) — the covering is on the hearers, not in the message. The gospel itself is not unclear or insufficient.</p>',
    "4": '<p><em>En hois ho theos tou aionos toutou</em>: the god of this age (<em>aion</em>, dispute level 2 — the present temporal age). MKT \'age\' — precise: the adversary is the ruling power of the period between Christ\'s comings, not \'the world\' spatially. <em>Etyphlose ta noemata ton apiston</em>: blinded the minds/thoughts. <em>Eis to me augasai ton photismon tou euangeliou tes doxes tou Christou</em>: so they cannot see the gospel\'s light of Christ\'s glory. The adversary\'s strategy is epistemic blindness, not direct power.</p>',
    "5": '<p><em>Ou gar heautous keryssomen alla Iesoun Christon Kyrion</em>: for we do not preach ourselves but Jesus Christ as Lord. The not-ourselves/Christ-as-Lord contrast is the anti-boasting principle applied to preaching. <em>Heautous de doulous hymon dia Iesoun</em>: ourselves as slaves (<em>douloi</em>) of you through Jesus — the apostle is slave of the congregation on account of Jesus.</p>',
    "6": '<p><em>Hoti ho theos ho eipon ek skotous phos lampsei</em>: the God who said \'out of darkness light shall shine\' — Gen 1:3 applied to the new creation. <em>Hos elampsen en tais kardiais hemon pros photismon tes gnoseos tes doxes tou theou en prosopo Christou</em>: who shone in our hearts to give the light of the knowledge of God\'s glory in the face of Christ. Creation light-event replicated in conversion: God\'s creative word lights the inner darkness. \'In the face of Christ\' — the face where God\'s glory is now visible, replacing the veiled face of Moses.</p>',
    "8": '<p><em>En panti thlibomenoi all\' ou stenochoroymenoi</em>: pressed (<em>thlibo</em>) on every side but not crushed/hemmed in (<em>stenochoreo</em>). The peristasis catalogue (4:8-9): four pairs of contradictions, each with a negative and a limit. Structure is deliberate — real danger but the danger does not define the final word. <em>Aporoymenoi all\' ouk exaporoymenoi</em>: at a loss (<em>aporeo</em>) but not utterly at a loss — the intensified prefix <em>ex-</em> marks the absolute limit not reached.</p>',
    "9": '<p><em>Diokomenoi all\' ouk enkataleipoumenoi</em>: persecuted but not forsaken (<em>egkataleipo</em> — the verb of Ps 22:1, the dereliction cry). Divine non-abandonment stands even in persecution. <em>Kataballomenoi all\' ouk apollymenoi</em>: struck down but not destroyed (<em>apollymi</em> — same verb as \'perishing\' in v.3). Paul is in the same category of danger as those spiritually perishing, but the outcome differs because of Christ.</p>',
    "10": '<p><em>Pantote ten nekrosin tou Iesou en to somati peripherontes</em>: always carrying in the body the dying (<em>nekrosis</em>) of Jesus — specifically Jesus\' death-pattern, not just mortality in general. <em>Hina kai he zoe tou Iesou en to somati hemon phaneroth e</em>: so that Jesus\' life may be manifested in our body. The Christological logic of display: the community sees the living Christ through Paul\'s endurance of death.</p>',
    "11": '<p><em>Aei gar hemeis hoi zontes eis thanaton paradidometha dia Iesoun</em>: we who are living are always being handed over (<em>paradidomi</em> — the betrayal/delivery verb, used for Jesus\' delivery to death) for Jesus\' sake. <em>Sarx</em> (dispute level 2) here: the physical, mortal body — the vulnerable mortality of the human frame, not the sinful principle. The life of Jesus manifested in mortal flesh is the apostolic witness.</p>',
    "12": '<p><em>Hoste ho thanatos en hemin energeitai, he de zoe en hymin</em>: death is working (<em>energeo</em>) in us, life in you. The transfer-logic: Paul absorbs the dying so the community receives the life. Peristasis-suffering is not random hardship but apostolic service — the carrying of death enables the community\'s experience of life.</p>',
    "13": '<p><em>Echontes de to auto pneuma tes pisteos kata to gegrammenon</em>: having the same spirit of faith according to what is written — Ps 116:10 (LXX): \'I believed, therefore I spoke.\' <em>Pistis</em> (dispute level 2): Paul cites the Psalmist\'s speech-from-faith as his model. Faith in the resurrection-God produces speech — the ground of the continuation of apostolic proclamation in the face of death.</p>',
    "14": '<p><em>Eidos hoti ho egeias ton Kyrion Iesoun kai hemas syn Iesou egerei</em>: knowing that the one who raised the Lord Jesus will also raise us with Jesus. <em>Kai parasteisei syn hymin</em>: and will present us together with you. The resurrection hope encompasses both Paul and community — raised and presented together. The <em>syn</em>-prefix: resurrection is communal, not solitary.</p>',
    "15": '<p><em>Ta gar panta di\' hymas</em>: all of this is for your sake. <em>Hina he charis pleonousa dia ton pleionon ten eucharistian perisseuse eis ten doxan tou theou</em>: so that grace (<em>charis</em>, dispute level 2), as it spreads, may increase thanksgiving. <em>Eucharistia</em> overflowing to God\'s glory is the telos of apostolic mission.</p>',
    "16": '<p><em>Dio ouk ekkakomen</em>: therefore we do not lose heart — the refrain of 4:1 repeated, forming an <em>inclusio</em> around the peristasis catalogue. <em>Ho exo hemon anthropos diaphtheitai</em>: the outer person is wasting away (<em>diaphtheiro</em>). <em>Ho eso hemon anakainoytai hemera kai hemera</em>: the inner person is being renewed day by day — progressive outward decay matched by progressive inward renewal.</p>',
    "17": '<p><em>To gar parautika elaphron tes thlipseos hemon kath\' hyperbolen eis hyperbolen aionion baros doxes katergazetai hemin</em>: the momentary lightness of affliction (<em>elaphron</em> — same root as \'fickle\' in 1:17, here ironic) is working (<em>katergazomai</em>) an eternal weight of glory beyond all comparison. <em>Aionios</em> (dispute level 2 — eternal/everlasting): the eschatological duration of glory contrasts with the temporal affliction. Light-and-momentary vs heavy-and-eternal reversal.</p>',
    "18": '<p><em>Me skopoynton hemon ta blepomena alla ta me blepomena</em>: not attending to (<em>skopeo</em> — scoping, fixing attention on) the visible things but the invisible. <em>Ta gar blepomena proskaira, ta de me blepomena aionios</em>: visible things are temporary (<em>proskairos</em> — seasonal, for a time); invisible things eternal (<em>aionios</em>). The epistemological reorientation grounds apostolic endurance in a different mode of perception — faith that sees the eternal behind the temporal.</p>'
  },
  "5": {
    "1": '<p><em>Oikia tou skeynous</em>: tent-house (<em>skenos</em> — tent, temporary dwelling). <em>Oikodome ek theou, oikia achiropoietos aionios en tois ouranois</em>: a building from God, not hand-made, eternal, heavenly — three qualities contrasting with the earthly tent. The eschatological body as permanent divine construction vs the temporary mortal body as fragile tent.</p>',
    "2": '<p><em>To oiketerion hemon to ex ouranou ependysasthai epipothountes</em>: longing to put on over (<em>ependyzomai</em> — clothe over existing clothing) our heavenly dwelling. The eschatological body is not replacement but clothing-over: Paul seems to prefer transformation at the Parousia without passing through the naked intermediate state of death.</p>',
    "3": '<p><em>Ei ge kai endysamenoi ou gymnoi heurethesometha</em>: if indeed, having put it on, we will not be found naked (<em>gymnos</em>). Nakedness = the disembodied state of death before resurrection. Paul\'s hope is not disembodiment (Greek philosophical idealism) but the heavenly body as new clothing. The <em>ei ge</em> conditional acknowledges the alternative: some may die before the Parousia.</p>',
    "4": '<p><em>Hoi ontes en to skenei stenaZomen baroymenoi</em>: those in the tent groan, being burdened (<em>bareo</em> — same burden-verb as 1:8). <em>Eph\' ho ou thelomen ekdysasthai all\' ependysasthai</em>: not wishing to be unclothed (<em>ekdyomai</em>) but clothed over (<em>ependyomai</em>). <em>Hina katapoth e to thneton hypo tes zoes</em>: that the mortal may be swallowed up by life (reverse of 2:7 where grief \'swallows\' the offender — the eschatological swallowing of death by life).</p>',
    "5": '<p><em>Ho de katergasamenos hemas eis auto touto theos, ho dous hemon ton arrhabona tou pneumatos</em>: the one who fashioned/prepared us for this very purpose is God, who gave the Spirit as <em>arrabon</em> (pledge/down-payment — commercial-legal term). The Spirit as earnest of the eschatological body: the bodily resurrection hope is guaranteed by the Spirit\'s present indwelling.</p>',
    "6": '<p><em>Tharrountes oun pantote</em>: being confident therefore always. <em>Endemountes en to somati ekdemoumen apo tou Kyriou</em>: being at home in the body (<em>endemeuo</em>) we are away from (<em>ekdemeuo</em>) the Lord. The spatial metaphor: physical embodiment is away-from-the-Lord — not sinful but the condition of the present age before the Parousia and full presence with Christ.</p>',
    "7": '<p><em>Dia pisteos gar peripatoumen, ou dia eidous</em>: we walk (<em>peripateo</em> — conduct our lives) by faith (<em>pistis</em>, dispute level 2), not by sight (<em>eidos</em> — visible appearance). Condenses 4:18\'s epistemological reorientation: present life conducted by confident trust in the unseen, grounded in the resurrection-God\'s faithfulness established throughout ch 1.</p>',
    "8": '<p><em>Tharroymen de kai eudokoymen mallon ekdemesai ek tou somatos kai endemesai pros ton Kyrion</em>: we prefer (<em>eudokeo</em> — take pleasure in) to be away from the body and at home with the Lord. This clarifies 5:6: the intermediate state (death before resurrection) is \'at home with the Lord\' even if not the final goal. Paul\'s preference is personal presence with Christ in any bodily form.</p>',
    "9": '<p><em>Dio kai philotimoymetha eite endemoyntes eite ekdemoyntes euarestoi auto einai</em>: we make it our ambition (<em>philotimeomai</em> — love of honor; here sanctified: Paul\'s goal is Christ\'s approval, not human recognition) to be well-pleasing to him. The Parousia judgment (v.10) grounds present moral effort regardless of the believer\'s state at any given moment.</p>',
    "10": '<p><em>Tous gar pantas hemas phanerothena dei emprosthen tou bematos tou Christou</em>: we must all appear (<em>phaneroo</em> — be made manifest, become fully visible) before the <em>bema</em> (judgment seat) of Christ. <em>Bema</em>: the raised platform/tribunal for judgments — the Roman magistrate\'s seat (Paul stood before Gallio\'s bema in Acts 18:12; he projects all believers before Christ\'s). <em>Ta dia tou somatos</em>: the things done through the body — bodily actions have eschatological weight.</p>',
    "11": '<p><em>Eidos oun ton phobon tou Kyriou anthropous peithomen</em>: knowing the fear of the Lord (<em>phobos tou Kyriou</em>) we persuade people. Paul\'s evangelism is grounded in reverent awe before Christ\'s bema. <em>Theo de pephanerome tha</em>: to God we have been made manifest — transparent accountability before God grounds the apostolic persuasion.</p>',
    "12": '<p><em>Ou palin heautous synistanomen hymin alla aphorm en didontes hymin kauchematos hyper hemon</em>: not again commending ourselves but giving opportunity (<em>aphorme</em> — a launching pad) for boasting about us. Paul arms the Corinthians against the super-apostles by providing genuine knowledge of his apostolic character. The opponents boast in face/appearance (<em>prosopon</em>) rather than heart.</p>',
    "13": '<p><em>Eite gar exestemen, theo</em>: if we are out of our minds (<em>existemi</em> — ecstatic, beside ourselves; probably referencing charismatic experiences or the intense letters), it is for God. <em>Eite sophronoumen, hymin</em>: if in our right mind, it is for you. The ecstasy-or-sobriety binary covers all apostolic modes: both states serve their purpose. Paul refuses to be categorized by the opponents\' criteria.</p>',
    "14": '<p><em>He gar agape tou Christou synechei hemas</em>: the love of Christ holds together/constrains (<em>synecho</em> — presses together, compels). <em>Agape tou Christou</em>: genitive ambiguous — Christ\'s love for us (subjective, favored by context) or our love for Christ. <em>Krinantas touto hoti heis hyper panton apethanen</em>: having concluded that one died for all, therefore all died. Substitutionary-participatory atonement: the one died as all, so all are reckoned as having died.</p>',
    "15": '<p><em>Kai hyper panton apethanen hina hoi zontes meketi heautois zosin alla to hyper auton apothanonti kai egerthen ti</em>: he died for all so that the living might no longer live for themselves (<em>heautois</em> — self-oriented) but for him who died and was raised. The purpose of the atonement is the redirection of life-orientation. The resurrection is included: not just substitutionary death but the raised-and-living Christ who now claims the lives he redeemed.</p>',
    "16": '<p><em>Hoste hemeis apo tou nyn oudena oidamen kata sarka</em>: from now on we know no one according to flesh (<em>kata sarka</em>). The death-resurrection event (vv.14-15) creates a new epistemological standpoint. <em>Ei kai egnokamen kata sarka Christon, alla nyn ouketi ginoskomen</em>: even if we once knew Christ according to flesh, now we know him thus no longer. <em>Kata sarka</em>: MKT \'from a worldly point of view\'; the literal \'according to flesh\' carries more weight — evaluation by human lineage, social status, religious credentials is replaced by the new-creation perspective.</p>',
    "18": '<p><em>Ta de panta ek tou theou tou katallagantos hemas heauto dia Christou</em>: all things are from God who reconciled (<em>katallasso</em> — resolved the enmity; aorist) us to himself through Christ. <em>Kai dontos hemin ten diakonian tes katalages</em>: and gave us the ministry of reconciliation. The reconciliation is accomplished before the ministry of announcement begins — the apostle announces what God has already done.</p>',
    "19": '<p><em>Hos hoti theos en en Christo kosmon katallasson heauto</em>: that God was in Christ reconciling the world to himself. <em>Me logizomenos autois ta paraptomata auton</em>: not counting their trespasses against them (<em>logizomai</em> — the ledger-verb of imputation). The reconciliation involves cancellation of the sin-debt — divine non-imputation as the mechanism of reconciliation.</p>',
    "20": '<p><em>Hyper Christou oun presbeuomen, hos tou theou parakalountos di\' hemon</em>: we are ambassadors (<em>presbytero</em> — official representatives with delegated authority) for Christ, as though God were making his appeal through us. The apostle is not a freelance preacher but an official envoy. <em>Deometha hyper Christou: katallagete to theo</em>: we beg on behalf of Christ — be reconciled to God. The urgency comes from knowing the bema (v.10) is coming.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', '2corinthians')
    merge_comm(existing, ORIGINAL)
    save_comm('mkt-original', '2corinthians', existing)
    for ch in ['1', '2', '3', '4', '5']:
        count = len(existing.get(ch, {}))
        print(f'  ch{ch}: {count} entries')

